const Input = ({ icon, alt, type = 'text', placeholder, value, onChange, className }) => {
  return (
    <div>
      <div>
        <img src={icon} alt={alt} style={{ width: '60%', height: '60%' }} />
      </div>
      <div>
        <input
          className={roundedTextBox['input-field']} 
          type={type}
          placeholder={placeholder}
          value={value}
          onChange={onChange}
        />
      </div>
    </div>
  );
};

export default Input;
